import string


def check(s):
    c = 0
    for i in range(len(s) - 1):
        if s[i] == s[i + 1]:
            c += 1
    if c > 0:
        return False
    else:
        return True


n, k = map(int, input().split())
password = []
for i in string.ascii_lowercase:
    password.append(i)

for i in range(k, n + 1):
    for j in range(i):
        if check(password[j:j + i]):
            print(''.join(password[j:j + i]))
            break
